    "content": "{"content":"// SPDX-License-Identifier: GPL-2.0\n/*\n * Common Code for Data Access Monitoring\n *\n * Author: SeongJae Park <sj@kernel.org>\n */\n\n#include <linux/migrate.h>\n#include <linux/mmu_notifier.h>\n#include <linux/page_idle.h>\n#include <linux/pagemap.h>\n#include <linux/rmap.h>\n#include <linux/swap.h>\n#include <linux/leafops.h>\n\n#include \"../internal.h\"\n#include \"ops-common.h\"\n\n/*\n * Get an online page for a pfn if it's in the LRU list.  Otherwise, returns\n * NULL.\n *\n * The body of this function is stolen from the 'page_idle_get_folio()'.  We\n * steal rather than reuse it because the code is quite simple.\n */\nstruct folio *damon_get_folio(unsigned long pfn)\n{\n\tstruct page *page = pfn_to_online_page(pfn);\n\tstruct folio *folio;\n\n\tif (!page)\n\t\treturn NULL;\n\n\tfolio = page_folio(page);\n\tif (!folio_test_lru(folio) || !folio_try_get(folio))\n\t\treturn NULL;\n\tif (unlikely(page_folio(page) != folio || !folio_test_lru(folio))) {\n\t\tfolio_put(folio);\n\t\tfolio = NULL;\n\t}\n\treturn folio;\n}\n\nvoid damon_ptep_mkold(pte_t *pte, struct vm_area_struct *vma, unsigned long addr)\n{\n\tpte_t pteval = ptep_get(pte);\n\tstruct folio *folio;\n\tbool young = false;\n\tunsigned long pfn;\n\n\tif (likely(pte_present(pteval)))\n\t\tpfn = pte_pfn(pteval);\n\telse\n\t\tpfn = softleaf_to_pfn(softleaf_from_pte(pteval));\n\n\tfolio = damon_get_folio(pfn);\n\tif (!folio)\n\t\treturn;\n\n\t/*\n\t * PFN swap PTEs, such as device-exclusive ones, that actually map pages\n\t * are \"old\" from a CPU perspective. The MMU notifier takes care of any\n\t * device aspects.\n\t */\n\tif (likely(pte_present(pteval)))\n\t\tyoung |= ptep_test_and_clear_young(vma, addr, pte);\n\tyoung |= mmu_notifier_clear_young(vma->vm_mm, addr, addr + PAGE_SIZE);\n\tif (young)\n\t\tfolio_set_young(folio);\n\n\tfolio_set_idle(folio);\n\tfolio_put(folio);\n}\n\nvoid damon_pmdp_mkold(pmd_t *pmd, struct vm_area_struct *vma, unsigned long addr)\n{\n#ifdef CONFIG_TRANSPARENT_HUGEPAGE\n\tpmd_t pmdval = pmdp_get(pmd);\n\tstruct folio *folio;\n\tbool young = false;\n\tunsigned long pfn;\n\n\tif (likely(pmd_present(pmdval)))\n\t\tpfn = pmd_pfn(pmdval);\n\telse\n\t\tpfn = softleaf_to_pfn(softleaf_from_pmd(pmdval));\n\n\tfolio = damon_get_folio(pfn);\n\tif (!folio)\n\t\treturn;\n\n\tif (likely(pmd_present(pmdval)))\n\t\tyoung |= pmdp_test_and_clear_young(vma, addr, pmd);\n\tyoung |= mmu_notifier_clear_young(vma->vm_mm, addr, addr + HPAGE_PMD_SIZE);\n\tif (young)\n\t\tfolio_set_young(folio);\n\n\tfolio_set_idle(folio);\n\tfolio_put(folio);\n#endif /* CONFIG_TRANSPARENT_HUGEPAGE */\n}\n\n#define DAMON_MAX_SUBSCORE\t(100)\n#define DAMON_MAX_AGE_IN_LOG\t(32)\n\nint damon_hot_score(struct damon_ctx *c, struct damon_region *r,\n\t\t\tstruct damos *s)\n{\n\tint freq_subscore;\n\tunsigned int age_in_sec;\n\tint age_in_log, age_subscore;\n\tunsigned int freq_weight = s->quota.weight_nr_accesses;\n\tunsigned int age_weight = s->quota.weight_age;\n\tint hotness;\n\n\tfreq_subscore = r->nr_accesses * DAMON_MAX_SUBSCORE /\n\t\tdamon_max_nr_accesses(&c->attrs);\n\n\tage_in_sec = (unsigned long)r->age * c->attrs.aggr_interval / 1000000;\n\tfor (age_in_log = 0; age_in_log < DAMON_MAX_AGE_IN_LOG && age_in_sec;\n\t\t\tage_in_log++, age_in_sec >>= 1)\n\t\t;\n\n\t/* If frequency is 0, higher age means it's colder */\n\tif (freq_subscore == 0)\n\t\tage_in_log *= -1;\n\n\t/*\n\t * Now age_in_log is in [-DAMON_MAX_AGE_IN_LOG, DAMON_MAX_AGE_IN_LOG].\n\t * Scale it to be in [0, 100] and set it as age subscore.\n\t */\n\tage_in_log += DAMON_MAX_AGE_IN_LOG;\n\tage_subscore = age_in_log * DAMON_MAX_SUBSCORE /\n\t\tDAMON_MAX_AGE_IN_LOG / 2;\n\n\thotness = (freq_weight * freq_subscore + age_weight * age_subscore);\n\tif (freq_weight + age_weight)\n\t\thotness /= freq_weight + age_weight;\n\t/*\n\t * Transform it to fit in [0, DAMOS_MAX_SCORE]\n\t */\n\thotness = hotness * DAMOS_MAX_SCORE / DAMON_MAX_SUBSCORE;\n\n\treturn hotness;\n}\n\nint damon_cold_score(struct damon_ctx *c, struct damon_region *r,\n\t\t\tstruct damos *s)\n{\n\tint hotness = damon_hot_score(c, r, s);\n\n\t/* Return coldness of the region */\n\treturn DAMOS_MAX_SCORE - hotness;\n}\n\nstatic bool damon_folio_mkold_one(struct folio *folio,\n\t\tstruct vm_area_struct *vma, unsigned long addr, void *arg)\n{\n\tDEFINE_FOLIO_VMA_WALK(pvmw, folio, vma, addr, 0);\n\n\twhile (page_vma_mapped_walk(&pvmw)) {\n\t\taddr = pvmw.address;\n\t\tif (pvmw.pte)\n\t\t\tdamon_ptep_mkold(pvmw.pte, vma, addr);\n\t\telse\n\t\t\tdamon_pmdp_mkold(pvmw.pmd, vma, addr);\n\t}\n\treturn true;\n}\n\nvoid damon_folio_mkold(struct folio *folio)\n{\n\tstruct rmap_walk_control rwc = {\n\t\t.rmap_one = damon_folio_mkold_one,\n\t\t.anon_lock = folio_lock_anon_vma_read,\n\t};\n\n\tif (!folio_mapped(folio) || !folio_raw_mapping(folio)) {\n\t\tfolio_set_idle(folio);\n\t\treturn;\n\t}\n\n\tif (!folio_trylock(folio))\n\t\treturn;\n\n\trmap_walk(folio, &rwc);\n\tfolio_unlock(folio);\n\n}\n\nstatic bool damon_folio_young_one(struct folio *folio,\n\t\tstruct vm_area_struct *vma, unsigned long addr, void *arg)\n{\n\tbool *accessed = arg;\n\tDEFINE_FOLIO_VMA_WALK(pvmw, folio, vma, addr, 0);\n\tpte_t pte;\n\n\t*accessed = false;\n\twhile (page_vma_mapped_walk(&pvmw)) {\n\t\taddr = pvmw.address;\n\t\tif (pvmw.pte) {\n\t\t\tpte = ptep_get(pvmw.pte);\n\n\t\t\t/*\n\t\t\t * PFN swap PTEs, such as device-exclusive ones, that\n\t\t\t * actually map pages are \"old\" from a CPU perspective.\n\t\t\t * The MMU notifier takes care of any device aspects.\n\t\t\t */\n\t\t\t*accessed = (pte_present(pte) && pte_young(pte)) ||\n\t\t\t\t!folio_test_idle(folio) ||\n\t\t\t\tmmu_notifier_test_young(vma->vm_mm, addr);\n\t\t} else {\n#ifdef CONFIG_TRANSPARENT_HUGEPAGE\n\t\t\tpmd_t pmd = pmdp_get(pvmw.pmd);\n\n\t\t\t*accessed = (pmd_present(pmd) && pmd_young(pmd)) ||\n\t\t\t\t!folio_test_idle(folio) ||\n\t\t\t\tmmu_notifier_test_young(vma->vm_mm, addr);\n#else\n\t\t\tWARN_ON_ONCE(1);\n#endif\t/* CONFIG_TRANSPARENT_HUGEP