 the damon_operations to check if registered.\nmm/damon/core.c:45: *\nmm/damon/core.c:46: * Return: true if the ops is set, false otherwise.\nmm/damon/core.c:47: */\nmm/damon/core.c:48:bool damon_is_registered_ops(enum damon_ops_id id)\nmm/damon/core.c:49:{\nmm/damon/core.c:50:\tbool registered;\nmm/damon/core.c:51:\nmm/damon/core.c:52:\tif (id >= NR_DAMON_OPS)\nmm/damon/core.c:53:\t\treturn false;\nmm/damon/core.c:54:\tmutex_lock(&damon_ops_lock);\nmm/damon/core.c:55:\tregistered = __damon_is_registered_ops(id);\nmm/damon/core.c:56:\tmutex_unlock(&damon_ops_lock);\nmm/damon/core.c:57:\treturn registered;\nmm/damon/core.c:58:}\nmm/damon/core.c:59:\nmm/damon/core.c:60:/**\nmm/damon/core.c:61: * damon_register_ops() - Register a monitoring operations set to DAMON.\nmm/damon/core.c:62: * @ops:\tmonitoring operations set to register.\nmm/damon/core.c:63: *\nmm/damon/core.c:64: * This function registers a monitoring operations set of valid &struct\nmm/damon/core.c:65: * damon_operations->id so that others can find and use them later.\nmm/damon/core.c:66: *\nmm/damon/core.c:67: * Return: 0 on success, negative error code otherwise.\nmm/damon/core.c:68: */\nmm/damon/core.c:69:int damon_register_ops(struct damon_operations *ops)\nmm/damon/core.c:70:{\nmm/damon/core.c:71:\tint err = 0;\nmm/damon/core.c:72:\nmm/damon/core.c:73:\tif (ops->id >= NR_DAMON_OPS)\nmm/damon/core.c:74:\t\treturn -EINVAL;\nmm/damon/core.c:75:\nmm/damon/core.c:76:\tmutex_lock(&damon_ops_lock);\nmm/damon/core.c:77:\t/* Fail for already registered ops */\nmm/damon/core.c:78:\tif (__damon_is_registered_ops(ops->id))\nmm/damon/core.c:79:\t\terr = -EINVAL;\nmm/damon/core.c:80:\telse\nmm/damon/core.c:81:\t\tdamon_registered_ops[ops->id] = *ops;\nmm/damon/core.c:82:\tmutex_unlock(&damon_ops_lock);\nmm/damon/core.c:83:\treturn err;\nmm/damon/core.c:84:}\nmm/damon/core.c:85:\nmm/damon/core.c:86:/**\nmm/damon/core.c:87: * damon_select_ops() - Select a monitoring operations to use with the context.\nmm/damon/core.c:88: * @ctx:\tmonitoring context to use the operations.\nmm/damon/core.c:89: * @id:\t\tid of the registered monitoring operations to select.\nmm/damon/core.c:90: *\nmm/damon/core.c:91: * This function finds registered monitoring operations set of @id and make\nmm/damon/core.c:92: * @ctx to use it.\nmm/damon/core.c:93: *\nmm/damon/core.c:94: * Return: 0 on success, negative error code otherwise.\nmm/damon/core.c:95: */\nmm/damon/core.c:96:int damon_select_ops(struct damon_ctx *ctx, enum damon_ops_id id)\nmm/damon/core.c:97:{\nmm/damon/core.c:98:\tint err = 0;\nmm/damon/core.c:99:\nmm/damon/core.c:100:\tif (id >= NR_DAMON_OPS)\nmm/damon/core.c:101:\t\treturn -EINVAL;\nmm/damon/core.c:102:\nmm/damon/core.c:103:\tmutex_lock(&damon_ops_lock);\nmm/damon/core.c:104:\tif (!__damon_is_registered_ops(id))\nmm/damon/core.c:105:\t\terr = -EINVAL;\nmm/damon/core.c:106:\telse\nmm/damon/core.c:107:\t\tctx->ops = damon_registered_ops[id];\nmm/damon/core.c:108:\tmutex_unlock(&damon_ops_lock);\nmm/damon/core.c:109:\treturn err;\nmm/damon/core.c:110:}\nmm/damon/core.c:111:\nmm/damon/core.c:112:#ifdef CONFIG_DAMON_DEBUG_SANITY\nmm/damon/core.c:113:static void damon_verify_new_region(unsigned long start, unsigned long end)\nmm/damon/core.c:114:{\nmm/damon/core.c:115:\tWARN_ONCE(start >= end, \"start %lu >= end %lu\\n\", start, end);\nmm/damon/core.c:116:}\nmm/damon/core.c:117:#else\nmm/damon/core.c:118:static void damon_verify_new_region(unsigned long start, unsigned long end)\nmm/damon/core.c:119:{\nmm/damon/core.c:120:}\nmm/damon/core.c:121:#endif\nmm/damon/core.c:122:\nmm/damon/core.c:123:/*\nmm/damon/core.c:124: * Construct a damon_region struct\nmm/damon/core.c:125: *\nmm/damon/core.c:126: * Returns the pointer to the new struct if success, or NULL otherwise\nmm/damon/core.c:127: */\nmm/damon/core.c:128:struct damon_region *damon_new_region(unsigned long start, unsigned long end)\nmm/damon/core.c:129:{\nmm/damon/core.c:130:\tstruct damon_region *region;\nmm/damon/core.c:131:\nmm/damon/core.c:132:\tdamon_verify_new_region(start, end);\nmm/damon/core.c:133:\tregion = kmem_cache_alloc(damon_region_cache, GFP_KERNEL);\nmm/damon/core.c:134:\tif (!region)\nmm/damon/core.c:135:\t\treturn NULL;\nmm/damon/core.c:136:\nmm/damon/core.c:137:\tregion->ar.start = start;\nmm/damon/core.c:138:\tregion->ar.end = end;\nmm/damon/core.c:139:\tregion->nr_accesses = 0;\nmm/damon/core.c:140:\tregion->nr_accesses_bp = 0;\nmm/damon/core.c:141:\tINIT_LIST_HEAD(&region->list);\nmm/damon/core.c:142:\nmm/damon/core.c:143:\tregion->age = 0;\nmm/damon/core.c:144:\tregion->last_nr_accesses = 0;\nmm/damon/core.c:145:\nmm/damon/core.c:146:\treturn region;\nmm/damon/core.c:147:}\nmm/damon/core.c:148:\nmm/damon/core.c:149:void damon_add_region(struct damon_region *r, struct damon_target *t)\nmm/damon/core.c:150:{\nmm/damon/core.c:151:\tlist_add_tail(&r->list, &t->regions_list);\nmm/damon/core.c:152:\tt->nr_regions++;\nmm/damon/core.c:153:}\nmm/damon/core.c:154:\nmm/damon/core.c:155:#ifdef CONFIG_DAMON_DEBUG_SANITY\nmm/damon/core.c:156:static void damon_verify_del_region(struct damon_target *t)\nmm/damon/core.c:157:{\nmm/damon/core.c:158:\tWARN_ONCE(t->nr_regions == 0, \"t->nr_regions == 0\\n\");\nmm/damon/core.c:159:}\nmm/damon/core.c:160:#else\nmm/damon/core.c:161:static void damon_verify_del_region(struct damon_target *t)\nmm/damon/core.c:162:{\nmm/damon/core.c:163:}\nmm/damon/core.c:164:#endif\nmm/damon/core.c:165:\nmm/damon/core.c:166:static void damon_del_region(struct damon_region *r, struct damon_target *t)\nmm/damon/core.c:167:{\nmm/damon/core.c:168:\tdamon_verify_del_region(t);\nmm/damon/core.c:169:\nmm/damon/core.c:170:\tlist_del(&r->list);\nmm/damon/core.c:171:\tt->nr_regions--;\nmm/damon/core.c:172:}\nmm/damon/core.c:173:\nmm/damon/core.c:174:static void damon_free_region(struct damon_region *r)\nmm/damon/core.c:175:{\nmm/damon/core.c:176:\tkmem_cache_free(damon_region_cache, r);\nmm/damon/core.c:177:}\nmm/damon/core.c:178:\nmm/damon/core.c:179:void damon_destroy_region(struct damon_region *r, struct damon_target *t)\nmm/damon/core.c:180:{\nmm/damon/core.c:181:\tdamon_del_region(r, t);\nmm/damon/core.c:182:\tdamon_free_region(r);\nmm/damon/core.c:183:}\nmm/damon/core.c:184:\nmm/damon/core.c:185:static bool damon_is_last_region(struct damon_region *r,\nmm/damon/core.c:186:\t\tstruct damon_target *t)\nmm/damon/core.c:187:{\nmm/damon/core.c:188:\treturn list_is_last(&r->list, &t->regions_list);\nmm/damon/core.c:189:}\nmm/damon/core.c:190:\nmm/damon/core.c:191:/*\nmm/damon/core.c:192: * Check whether a region is intersecting an address range\nmm/damon/core.c:193: *\nmm/damon/core.c:194: * Returns true if it is.\nmm/damon/core.c:195: */\nmm/damon/core.c:196:static bool damon_intersect(struct damon_region *r,\nmm/damon/core.c:197:\t\tstruct damon_addr_range *re)\nmm/damon/core.c:198:{\nmm/damon/core.c:199:\treturn !(r->ar.end <= re->start || re->end <= r->ar.start);\nmm/damon/core.c:200:}\nmm/damon/core.c:201:\nmm/damon/core.c:202:/*\nmm/damon/core.c:203: * Fill holes in regions with new regions.\nmm/damon/core.c:204: */\nmm/damon/core.c:205:static int damon_fill_regions_holes(struct damon_region *first,\nmm/damon/core.c:206:\t\tstruct damon_region *last, struct damon_target *t)\nmm/damon/core.c:207:{\nmm/damon/core.c:208:\tstruct damon_region *r = first;\nmm/damon/core.c:209:\nmm/damon/core.c:210:\tdamon_for_each_region_from(r, t) {\nmm/damon/core.c:211:\t\tstruct damon_region *next, *newr;\nmm/damon/core.c:212:\nmm/damon/core.c:213:\t\tif (r == last)\nmm/damon/core.c:214:\t\t\tbreak;\nmm/damon/core.c:215:\t\tnext = damon_next_region(r);\nmm/damon/core.c:216:\t\tif (r->ar.end != next->ar.start) {\nmm/damon/core.c:217:\t\t\tnewr = damon_new_region(r->ar.end, next->ar.start);\nmm/damon/core.c:218:\t\t\tif (!newr)\nmm/damon/core.c:219:\t\t\t\treturn -ENOMEM;\nmm/damon/core.c:220:\t\t\tdamon_insert_region(newr, r, next, t);\nmm/damon/core.c:221:\t\t}\nmm/damon/core.c:222:\t}\nmm/damon/core.c:223:\treturn 0;\nmm/damon/core.c:224:}\nmm/damon/core.c:225:\nmm/damon/core.c:226:/*\nmm/damon/core.c:227: * damon_set_regions() - Set regions of a target for given address ranges.\nmm/damon/core.c:228: * @t:\t\tthe given target.\nmm/damon/core.c:229: * @ranges:\tarray of new monitoring target ranges.\nmm/damon/core.c:230: * @nr_ranges:\tlength of @ranges.\nmm/damon/core.c:231: * @min_region_sz:\tminimum region size.\nmm/damon/core.c:232: *\nmm/damon/core.c:233: * This function adds new regions to, or modify existing regions of a\nmm/damon/core.c:234: * monitoring target to fit in specific ranges.\nmm/damon/core.c:235: *\nmm/damon/core.c:236: * Return: 0 if success, or negative error code otherwise.\nmm/damon/core.c:237: */\nmm/damon/core.c:238:int damon_set_regions(struct damon_target *t, struct damon_addr_range *ranges,\nmm/damon/core.c:239:\t\tunsigned int nr_ranges, unsigned long min_region_sz)\nmm/damon/core.c:240:{\nmm/damon/core.c:241:\tstruct damon_region *r, *next;\nmm/damon/core.c:242:\tunsigned int i;\nmm/damon/core.c:243:\tint err;\nmm/damon/core.c:244:\nmm/damon/core.c:245:\t/* Remove regions which are not in the new ranges */\nmm/damon/core.c:246:\tdamon_for_each_region_safe(r, next, t) {\nmm/damon/core.c:247:\t\tfor (i = 0; i < nr_ranges; i++) {\nmm/damon/core.c:248:\t\t\tif (damon_intersect(r, &ranges[i]))\nmm/damon/core.c:249:\t\t\t\tbreak;\nmm/damon/core.c:250:\t\t}\nmm/damon/core.c:251:\t\tif (i == nr_ranges)\nmm/damon/core.c:252:\t\t\tdamon_destroy_region(r, t);\nmm/damon/core.c:253:\t}\nmm/damon/core.c:254:\nmm/damon/core.c:255:\tr = damon_first_region(t);\nmm/damon/core.c:256:\t/* Add new regions or resize existing regions to fit in the ranges */\nmm/damon/core.c:257:\tfor (i = 0; i < nr_ranges; i++) {\nmm/damon/core.c:258:\t\tstruct damon_region *first = NULL, *last, *newr;\nmm/damon/core.c:259:\t\tstruct damon_addr_range *range;\nmm/damon/core.c:260:\nmm/damon/core.c:261:\t\trange = &ranges[i];\nmm/damon/core.c:262:\t\t/* Get the first/last regions intersecting with the range */\nmm/damon/core.c:263:\t\tdamon_for_each_region_from(r, t) {\nmm/damon/core.c:264:\t\t\tif (damon_intersect(r, range)) {\nmm/damon/core.c:265:\t\t\t\tif (!first)\nmm/damon/core.c:266:\t\t\t\t\tfirst = r;\nmm/damon/core.c:267:\t\t\t\tlast = r;\nmm/damon/core.c:268:\t\t\t}\nmm/damon/core.c:269:\t\t\tif (r->ar.start >= range->end)\nmm/damon/core.c:270:\t\t\t\tbreak;\nmm/damon/core.c:271:\t\t}\nmm/damon/core.c:272:\t\tif (!first) {\nmm/damon/core.c:273:\t\t\t/* no region intersects with this range */\nmm/damon/core.c:274:\t\t\tnewr = damon_new_region(\nmm/damon/core.c:275:\t\t\t\t\tALIGN_DOWN(range->start,\nmm/damon/core.c:276:\t\t\t\t\t\tmin_region_sz),\nmm/damon/core.c:277:\t\t\t\t\tALIGN(range->end, min_region_sz));\nmm/damon/core.c:278:\t\t\tif (!newr)\nmm/damon/core.c:279:\t\t\t\treturn -ENOMEM;\nmm/damon/core.c:280:\t\t\tdamon_insert_region(newr, damon_prev_region(r), r, t);\nmm/damon/core.c:281:\t\t} else {\nmm/damon/core.c:282:\t\t\t/* resize intersecting regions to fit in this range */\nmm/damon/core.c:283:\t\t\tfirst->ar.start = ALIGN_DOWN(range->start,\nmm/damon/core.c:284:\t\t\t\t\tmin_region_sz);\nmm/damon/core.c:285:\t\t\tlast->ar.end = ALIGN(range->end, min_region_sz);\nmm/damon/core.c:286:\nmm/damon/core.c:287:\t\t\t/* fill possible holes in the range */\nmm/damon/core.c:288:\t\t\terr = damon_fill_regions_holes(first, last, t);\nmm/damon/core.c:289:\t\t\tif (err)\nmm/damon/core.c:290:\t\t\t\treturn err;\nmm/damon/core.c:291:\t\t}\nmm/damon/core.c:292:\t}\nmm/damon/core.c:293:\treturn 0;\nmm/damon/core.c:294:}\nmm/damon/core.c:295:\nmm/damon/core.c:296:struct damos_filter *damos_new_filter(enum damos_filter_type type,\nmm/damon/core.c:297:\t\tbool matching, bool allow)\nmm/damon/core.c:298:{\nmm/damon/core.c:299:\tstruct damos_filter *filter;\nmm/damon/core.c:300:\nmm/damon/core.c:301:\tfilter = kmalloc_obj(*filter);\nmm/damon/core.c:302:\tif (!filter)\nmm/damon/core.c:303:\t\treturn NULL;\nmm/damon/core.c:304:\tfilter->type = type;\nmm/damon/core.c:305:\tfilt